#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate the area of a polygon using the shoelace formula
double calculateArea(int n, int x[], int y[]) {
    double area = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += (x[i] * y[j] - x[j] * y[i]);
    }
    return abs(area) / 2;
}

// Function to check if a point is inside a polygon
int isPointInside(int n, int x[], int y[], int px, int py) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        if ((y[i] > py) != (y[j] > py) && (px < (x[j] - x[i]) * (py - y[i]) / (y[j] - y[i]) + x[i])) {
            count++;
        }
    }
    return count % 2 == 1;
}

